import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter a string:");
        String input = scanner.nextLine();

        int bufferSize = 10; // Maximum buffer size
        char[] buffer = new char[bufferSize]; // Fixed size buffer

        // Copy input into buffer with length check
        for (int i = 0; i < Math.min(input.length(), bufferSize); i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Buffer overflow fixed!");
    }
}

